import{_ as i,C as s,o as t,c as o,a2 as a,b as l,w as n,a as d,E as c,a3 as h}from"./chunks/framework.B72_uj9U.js";const v=JSON.parse('{"title":"Warp Benchmark Results","description":"","frontmatter":{"title":"Warp Benchmark Results","status":"complete"},"headers":[],"relativePath":"research/agents/warp/benchmarks.md","filePath":"research/agents/warp/benchmarks.md"}'),m={name:"research/agents/warp/benchmarks.md"};function p(u,e,g,b,f,k){const r=s("Mermaid");return t(),o("div",null,[e[1]||(e[1]=a('<h1 id="benchmarks" tabindex="-1">Benchmarks <a class="header-anchor" href="#benchmarks" aria-label="Permalink to &quot;Benchmarks&quot;">​</a></h1><blockquote><p>Warp&#39;s agent performance has been evaluated on Terminal-Bench, the primary benchmark for terminal-based coding agents. Results vary significantly across model configurations, reflecting the multi-model architecture of the Oz platform.</p></blockquote><h2 id="terminal-bench-overview" tabindex="-1">Terminal-Bench Overview <a class="header-anchor" href="#terminal-bench-overview" aria-label="Permalink to &quot;Terminal-Bench Overview&quot;">​</a></h2><p><strong>Terminal-Bench</strong> is a benchmark suite designed to evaluate AI coding agents that operate in terminal environments. It tests agents on real-world software engineering tasks that require:</p><ul><li>Reading and understanding code</li><li>Executing shell commands</li><li>Modifying files</li><li>Running tests to verify changes</li><li>Multi-step problem solving</li><li>Terminal interaction proficiency</li></ul><h3 id="terminal-bench-2-0-vs-1-0" tabindex="-1">Terminal-Bench 2.0 vs 1.0 <a class="header-anchor" href="#terminal-bench-2-0-vs-1-0" aria-label="Permalink to &quot;Terminal-Bench 2.0 vs 1.0&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Terminal-Bench 1.0</th><th>Terminal-Bench 2.0</th></tr></thead><tbody><tr><td>Task complexity</td><td>Moderate</td><td>Higher</td></tr><tr><td>Task count</td><td>Smaller set</td><td>Expanded set</td></tr><tr><td>Evaluation</td><td>Pass/fail per task</td><td>More granular scoring</td></tr><tr><td>Terminal skills</td><td>Basic</td><td>Advanced (interactive, multi-step)</td></tr><tr><td>Leaderboard size</td><td>~20 entries</td><td>~60+ entries</td></tr></tbody></table><h2 id="warp-s-terminal-bench-2-0-results" tabindex="-1">Warp&#39;s Terminal-Bench 2.0 Results <a class="header-anchor" href="#warp-s-terminal-bench-2-0-results" aria-label="Permalink to &quot;Warp&#39;s Terminal-Bench 2.0 Results&quot;">​</a></h2><h3 id="summary-table" tabindex="-1">Summary Table <a class="header-anchor" href="#summary-table" aria-label="Permalink to &quot;Summary Table&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rank</th><th>Configuration</th><th>Score</th><th>Notes</th></tr></thead><tbody><tr><td>#31</td><td>Warp (config A)</td><td>61.2%</td><td>Best Warp 2.0 result</td></tr><tr><td>#36</td><td>Warp (config B)</td><td>59.1%</td><td>Mid-tier configuration</td></tr><tr><td>#52</td><td>Warp (config C)</td><td>50.1%</td><td>Lower-tier configuration</td></tr></tbody></table><h3 id="context-in-the-leaderboard" tabindex="-1">Context in the Leaderboard <a class="header-anchor" href="#context-in-the-leaderboard" aria-label="Permalink to &quot;Context in the Leaderboard&quot;">​</a></h3>',11)),(t(),l(h,null,{default:n(()=>[c(r,{id:"mermaid-192",class:"mermaid",graph:"xychart-beta%0A%20%20%20%20title%20%22Terminal-Bench%202.0%20Score%20Distribution%20(approximate)%22%0A%20%20%20%20x-axis%20%22Rank%22%20%5B1%2C%205%2C%2010%2C%2015%2C%2020%2C%2025%2C%2031%2C%2036%2C%2040%2C%2045%2C%2052%2C%2055%2C%2060%5D%0A%20%20%20%20y-axis%20%22Score%20(%25)%22%2030%20--%3E%2090%0A%20%20%20%20bar%20%5B88%2C%2085%2C%2080%2C%2078%2C%2075%2C%2072%2C%2061%2C%2059%2C%2056%2C%2053%2C%2050%2C%2047%2C%2044%5D%0A"})]),fallback:n(()=>[...e[0]||(e[0]=[d(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a(`<blockquote><p>▓ = Warp entries: Rank 31 (61.2%), Rank 36 (59.1%), Rank 52 (50.1%)</p></blockquote><h3 id="model-configuration-analysis" tabindex="-1">Model Configuration Analysis <a class="header-anchor" href="#model-configuration-analysis" aria-label="Permalink to &quot;Model Configuration Analysis&quot;">​</a></h3><p>Warp&#39;s multi-model support means different configurations yield different benchmark results. The spread between best (#31, 61.2%) and worst (#52, 50.1%) Warp results spans ~11 percentage points, indicating:</p><ol><li><strong>Model choice matters significantly</strong>: The underlying LLM has a major impact on agent performance, even with the same orchestration platform</li><li><strong>Auto modes vs. fixed models</strong>: The Auto modes (Cost-efficient, Responsive, Genius) may route to different models for different tasks, affecting consistency</li><li><strong>Terminal-specific skills</strong>: Some models may be better at terminal interaction patterns (command generation, output parsing) than others</li></ol><h3 id="possible-configuration-mapping" tabindex="-1">Possible Configuration Mapping <a class="header-anchor" href="#possible-configuration-mapping" aria-label="Permalink to &quot;Possible Configuration Mapping&quot;">​</a></h3><p>While exact configurations aren&#39;t publicly detailed, the three entries likely represent different model tiers:</p><table tabindex="0"><thead><tr><th>Config</th><th>Likely Model Tier</th><th>Score</th><th>Trade-off</th></tr></thead><tbody><tr><td>A (#31)</td><td>Genius / Top-tier model</td><td>61.2%</td><td>Best quality, highest cost</td></tr><tr><td>B (#36)</td><td>Responsive / Mid-tier</td><td>59.1%</td><td>Balanced speed/quality</td></tr><tr><td>C (#52)</td><td>Cost-efficient / Budget</td><td>50.1%</td><td>Lowest cost, adequate quality</td></tr></tbody></table><h2 id="warp-s-terminal-bench-1-0-results" tabindex="-1">Warp&#39;s Terminal-Bench 1.0 Results <a class="header-anchor" href="#warp-s-terminal-bench-1-0-results" aria-label="Permalink to &quot;Warp&#39;s Terminal-Bench 1.0 Results&quot;">​</a></h2><h3 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rank</th><th>Score</th><th>Notes</th></tr></thead><tbody><tr><td>#11</td><td>52.0%</td><td>Strong showing in original benchmark</td></tr></tbody></table><h3 id="_1-0-vs-2-0-performance" tabindex="-1">1.0 vs 2.0 Performance <a class="header-anchor" href="#_1-0-vs-2-0-performance" aria-label="Permalink to &quot;1.0 vs 2.0 Performance&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Warp Performance Across Benchmark Versions:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>         Terminal-Bench 1.0    Terminal-Bench 2.0</span></span>
<span class="line"><span>         ─────────────────    ─────────────────</span></span>
<span class="line"><span>Rank:         #11                 #31 / #36 / #52</span></span>
<span class="line"><span>Score:       52.0%              61.2% / 59.1% / 50.1%</span></span></code></pre></div><p><strong>Observations</strong>:</p><ul><li>Warp&#39;s best 2.0 score (61.2%) exceeds its 1.0 score (52.0%), suggesting improvement in the agent platform over time</li><li>The rank dropped from #11 to #31+ as more competitors entered the 2.0 leaderboard</li><li>The 2.0 benchmark is harder, so absolute score improvements may understate progress</li><li>Multiple 2.0 entries vs. single 1.0 entry reflects the multi-model configuration</li></ul><h2 id="comparative-analysis" tabindex="-1">Comparative Analysis <a class="header-anchor" href="#comparative-analysis" aria-label="Permalink to &quot;Comparative Analysis&quot;">​</a></h2><h3 id="how-warp-compares-to-other-terminal-agents" tabindex="-1">How Warp Compares to Other Terminal Agents <a class="header-anchor" href="#how-warp-compares-to-other-terminal-agents" aria-label="Permalink to &quot;How Warp Compares to Other Terminal Agents&quot;">​</a></h3><p>Based on publicly available Terminal-Bench data:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Terminal-Bench 2.0 — Selected Agents (approximate):</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Agent                        Best Score    Best Rank</span></span>
<span class="line"><span>─────────────────────────   ──────────    ─────────</span></span>
<span class="line"><span>Claude Code (Opus 4)          ~82%          ~#1-3</span></span>
<span class="line"><span>Codex CLI                     ~70%          ~#10-15</span></span>
<span class="line"><span>Warp (best config)            61.2%         #31</span></span>
<span class="line"><span>Aider (architect)             ~55-60%       ~#35-45</span></span></code></pre></div><blockquote><p><strong>Note</strong>: These comparisons are approximate. Terminal-Bench rankings change frequently as new entries are submitted and configurations are updated.</p></blockquote><h3 id="factors-affecting-warp-s-benchmark-performance" tabindex="-1">Factors Affecting Warp&#39;s Benchmark Performance <a class="header-anchor" href="#factors-affecting-warp-s-benchmark-performance" aria-label="Permalink to &quot;Factors Affecting Warp&#39;s Benchmark Performance&quot;">​</a></h3><p>Several factors may explain Warp&#39;s mid-tier benchmark ranking despite its advanced architecture:</p><ol><li><p><strong>Benchmark design</strong>: Terminal-Bench may not test the capabilities where Warp excels (interactive process control, block-level context, GPU UX). Benchmarks focus on file editing and test passing, where wrapper agents are equally capable.</p></li><li><p><strong>Orchestration overhead</strong>: Warp&#39;s rich context assembly and planning features may add latency or token overhead that doesn&#39;t help on benchmark tasks but is valuable for real-world usage.</p></li><li><p><strong>Multi-model routing</strong>: Auto modes may not always select the optimal model for each benchmark task, whereas dedicated agents using a single top model have consistency.</p></li><li><p><strong>Terminal-native vs. benchmark-optimal</strong>: Warp&#39;s architecture is optimized for the human-in-the-loop experience, not for fully autonomous benchmark execution.</p></li><li><p><strong>Closed-source optimization</strong>: Without access to Warp&#39;s internals, it&#39;s hard to know how much prompt engineering or benchmark-specific tuning has been done.</p></li></ol><h3 id="what-benchmarks-don-t-capture" tabindex="-1">What Benchmarks Don&#39;t Capture <a class="header-anchor" href="#what-benchmarks-don-t-capture" aria-label="Permalink to &quot;What Benchmarks Don&#39;t Capture&quot;">​</a></h3><p>Terminal-Bench measures autonomous task completion but does not evaluate:</p><table tabindex="0"><thead><tr><th>Unmeasured Capability</th><th>Warp Advantage</th></tr></thead><tbody><tr><td>Interactive debugging (GDB, REPL)</td><td>Full Terminal Use</td></tr><tr><td>Long-running dev server interaction</td><td>PTY monitoring</td></tr><tr><td>Human-agent collaboration quality</td><td>Takeover/handback</td></tr><tr><td>UX quality and trust-building</td><td>GPU-rendered rich UI</td></tr><tr><td>Team workflow integration</td><td>Cloud agents, Warp Drive</td></tr><tr><td>Error recovery with context</td><td>Block-level structured history</td></tr><tr><td>Multi-turn conversation management</td><td>Forking, compaction</td></tr></tbody></table><h2 id="performance-metrics-beyond-benchmarks" tabindex="-1">Performance Metrics Beyond Benchmarks <a class="header-anchor" href="#performance-metrics-beyond-benchmarks" aria-label="Permalink to &quot;Performance Metrics Beyond Benchmarks&quot;">​</a></h2><h3 id="rendering-performance-not-agent-but-notable" tabindex="-1">Rendering Performance (Not Agent, but Notable) <a class="header-anchor" href="#rendering-performance-not-agent-but-notable" aria-label="Permalink to &quot;Rendering Performance (Not Agent, but Notable)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metric</th><th>Value</th><th>Benchmark</th></tr></thead><tbody><tr><td>Frame rate</td><td>400+ fps</td><td>Measured on Apple Silicon</td></tr><tr><td>Average redraw</td><td>~1.9ms</td><td>Full terminal content</td></tr><tr><td>Input latency</td><td>Sub-frame</td><td>Keypress to render</td></tr><tr><td>Startup time</td><td>~200ms</td><td>Cold start to usable</td></tr></tbody></table><p>These rendering metrics matter for agent UX: fast rendering means agent output appears instantly, reducing perceived latency of the agent loop.</p><h3 id="cloud-agent-performance" tabindex="-1">Cloud Agent Performance <a class="header-anchor" href="#cloud-agent-performance" aria-label="Permalink to &quot;Cloud Agent Performance&quot;">​</a></h3><p>Cloud agent performance characteristics (from documentation):</p><ul><li><strong>Parallel execution</strong>: Multiple agents can run simultaneously</li><li><strong>Environment setup</strong>: Docker container startup adds baseline latency</li><li><strong>Trigger latency</strong>: Event → agent start varies by trigger type</li><li><strong>Session persistence</strong>: Sessions maintain state for async steering</li></ul><h2 id="benchmark-evolution" tabindex="-1">Benchmark Evolution <a class="header-anchor" href="#benchmark-evolution" aria-label="Permalink to &quot;Benchmark Evolution&quot;">​</a></h2><h3 id="what-would-a-terminal-native-benchmark-look-like" tabindex="-1">What Would a Terminal-Native Benchmark Look Like? <a class="header-anchor" href="#what-would-a-terminal-native-benchmark-look-like" aria-label="Permalink to &quot;What Would a Terminal-Native Benchmark Look Like?&quot;">​</a></h3><p>To properly evaluate Warp&#39;s unique capabilities, a benchmark would need tasks like:</p><ol><li><strong>Interactive debugging</strong>: Start GDB, find and fix a bug using debugger commands</li><li><strong>Dev server interaction</strong>: Start a dev server, detect errors, fix them while server runs</li><li><strong>REPL exploration</strong>: Use Python REPL to explore data, write analysis code</li><li><strong>Database interaction</strong>: Connect to database, explore schema, write migration</li><li><strong>Multi-tool workflow</strong>: Use git, docker, and language tools in concert</li><li><strong>Error recovery</strong>: Handle unexpected failures gracefully with terminal context</li><li><strong>Human collaboration</strong>: Tasks requiring handoff between human and agent</li></ol><h3 id="terminal-bench-3-0-potential" tabindex="-1">Terminal-Bench 3.0 Potential <a class="header-anchor" href="#terminal-bench-3-0-potential" aria-label="Permalink to &quot;Terminal-Bench 3.0 Potential&quot;">​</a></h3><p>Future benchmark versions may incorporate more interactive terminal tasks, which would better showcase Warp&#39;s Full Terminal Use capabilities and potentially improve its relative ranking.</p><h2 id="summary-1" tabindex="-1">Summary <a class="header-anchor" href="#summary-1" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Warp&#39;s benchmark performance places it in the <strong>middle tier</strong> of terminal-based coding agents on Terminal-Bench, with scores ranging from 50.1% to 61.2% depending on model configuration. While this is below top-ranked agents like Claude Code, the benchmarks primarily measure autonomous file editing — a task where wrapper agents have no structural disadvantage. Warp&#39;s unique strengths (Full Terminal Use, rich UX, cloud agents, team workflows) are largely untested by current benchmarks, suggesting that real-world value may diverge significantly from benchmark rankings.</p>`,40))])}const x=i(m,[["render",p]]);export{v as __pageData,x as default};
